mapper.select:

where c.user_id = #{userId}
  and c.is_deleted = false

    and c.status = #{status}

order by c.last_message_at desc nulls last, c.created_at desc
limit #{limit} offset #{offset}

select count(1)
from yx_conversation c
where c.user_id = #{userId}
  and c.is_deleted = false

    and c.status = #{status}
